#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,m,q,num0[N],num1[N];
vector<int> g[N];
struct node
{
	int num,tim;
};
void dij()
{
	queue<node> q;
	memset(num0,0x3f,sizeof(num0));
	memset(num1,0x3f,sizeof(num1));
	for(int i=0;i<g[1].size();i++)
	{
		int v=g[1][i];
		q.push(node{v,1});
	}
	while(!q.empty())
	{
		node t=q.front();
		q.pop();
		if(t.tim%2)
		{
			num1[t.num]=t.tim;
		}
		else num0[t.num]=t.tim;
		for(int i=0;i<g[t.num].size();i++)
		{
			int v=g[t.num][i];
			if(t.tim%2==1)
			{
				if(t.tim+1<=num0[v])
				{
					q.push(node{v,t.tim+1});
				}
			}
			else
			{
				if(t.tim+1<=num1[v])
				{
					q.push(node{v,t.tim+1});
				}
			}
		}
	}
}
int main()
{
	cin>>n>>m>>q;
	for(int i=1;i<=m;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dij();
	while(q--)
	{
		int a,l;
		cin>>a>>l;
		if(l%2)
		{
			if(num1[a]>l) cout<<"No";
			else cout<<"Yes";
		}
		else
		{
			if(num0[a]>l) cout<<"No";
			else cout<<"Yes";
		}
		cout<<"\n";
	}
	return 0;
}
